#include <stdlib.h>
#define _static_assert(condition, message) \
    ({ \
        if (!(condition)) { \
            fprintf(stderr, "Failed static assertion: %s\n", message); \
            exit(1); \
        } \
    })

int main()
{
    _static_assert(1, "This is a static assertion");
    return 0;
}

